/**
 * Anime-Sama.fun Automatic Scraper
 * Syncs anime data from anime-sama.fun WordPress API to FrivoxStream
 * 
 * Usage: bun run scripts/anime-sama-scraper.ts
 */

import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

// Anime-Sama.fun WordPress API
const API_BASE = 'https://anime-sama.fun/wp-json/wp/v2';
const SITE_BASE = 'https://anime-sama.fun';

interface WordPressPost {
  id: number;
  slug: string;
  title: { rendered: string };
  content: { rendered: string };
  excerpt: { rendered: string };
  link: string;
  featured_media: number;
  date: string;
  _embedded?: {
    'wp:featuredmedia'?: Array<{
      source_url: string;
    }>;
  };
}

interface ScrapedEpisode {
  number: number;
  sources: string[];
}

interface ScrapedAnime {
  slug: string;
  title: string;
  description: string;
  coverImage: string | null;
  episodes: ScrapedEpisode[];
  sourceUrl: string;
}

// Fetch all posts from WordPress API
async function fetchAllPosts(limit: number = 100): Promise<WordPressPost[]> {
  console.log('📊 Fetching total post count...');

  const response = await fetch(`${API_BASE}/posts?per_page=1`);
  const totalPages = parseInt(response.headers.get('x-wp-totalpages') || '0');
  const totalPosts = parseInt(response.headers.get('x-wp-total') || '0');

  console.log(`📊 Total animes found: ${totalPosts} (${totalPages} pages)`);

  const allPosts: WordPressPost[] = [];
  const pagesToFetch = Math.min(totalPages, Math.ceil(limit / 100));

  for (let page = 1; page <= pagesToFetch; page++) {
    console.log(`📄 Fetching page ${page}/${pagesToFetch}...`);

    try {
      const response = await fetch(
        `${API_BASE}/posts?per_page=100&page=${page}&_embed=1`
      );
      const posts = await response.json() as WordPressPost[];
      allPosts.push(...posts);

      // Rate limiting
      await sleep(300);
    } catch (error) {
      console.error(`❌ Error fetching page ${page}:`, error);
    }
  }

  return allPosts;
}

// Fetch anime page and extract episode video URLs
async function scrapeAnimeEpisodes(post: WordPressPost): Promise<ScrapedAnime> {
  const coverImage = post._embedded?.['wp:featuredmedia']?.[0]?.source_url || null;

  try {
    // Fetch the HTML page
    const response = await fetch(post.link);
    const html = await response.text();

    // Extract episode data from hidden divs
    // Format: <div class="eps">1!url1,url2,url3</div>
    const episodeRegex = /<div[^>]*class="eps"[^>]*>([^<]+)<\/div>/gi;
    const episodes: ScrapedEpisode[] = [];

    let match;
    while ((match = episodeRegex.exec(html)) !== null) {
      const data = match[1].trim();

      // Parse format: "episode_number!url1,url2,url3"
      if (data.includes('!')) {
        const [numStr, urlsStr] = data.split('!');
        const number = parseInt(numStr);
        const sources = urlsStr.split(',').filter(url => url.trim());

        if (!isNaN(number) && sources.length > 0) {
          episodes.push({ number, sources });
        }
      }
    }

    // Clean title
    const title = post.title.rendered
      .replace(/&#8211;/g, '-')
      .replace(/&#8217;/g, "'")
      .replace(/&#038;/g, '&')
      .replace(/&amp;/g, '&');

    // Clean description
    const description = post.excerpt.rendered
      .replace(/<[^>]*>/g, '')
      .replace(/&#8211;/g, '-')
      .replace(/&#8217;/g, "'")
      .replace(/&#038;/g, '&')
      .trim();

    return {
      slug: post.slug,
      title,
      description,
      coverImage,
      episodes,
      sourceUrl: post.link
    };
  } catch (error) {
    console.error(`❌ Error scraping ${post.slug}:`, error);
    return {
      slug: post.slug,
      title: post.title.rendered,
      description: '',
      coverImage,
      episodes: [],
      sourceUrl: post.link
    };
  }
}

// Detect source from URL
function detectSource(url: string): string {
  const urlLower = url.toLowerCase();

  if (urlLower.includes('uqload')) return 'uqload';
  if (urlLower.includes('vudeo')) return 'vudeo';
  if (urlLower.includes('younetu')) return 'younetu';
  if (urlLower.includes('streamvid')) return 'streamvid';
  if (urlLower.includes('sblongvu')) return 'sblongvu';
  if (urlLower.includes('streamhide')) return 'streamhide';
  if (urlLower.includes('vido.lol')) return 'vidolol';
  if (urlLower.includes('vvide0')) return 'vvide0';
  if (urlLower.includes('upstream.to')) return 'upstream';
  if (urlLower.includes('vidmoly')) return 'vidmoly';
  if (urlLower.includes('sibnet')) return 'sibnet';
  if (urlLower.includes('sendvid')) return 'sendvid';
  if (urlLower.includes('myvi')) return 'myvi';
  if (urlLower.includes('doodstream')) return 'doodstream';
  if (urlLower.includes('streamtape')) return 'streamtape';
  if (urlLower.includes('mixdrop')) return 'mixdrop';
  if (urlLower.includes('voe')) return 'voe';

  return 'unknown';
}

// Detect language from URL or title
function detectLanguage(url: string, title: string): string {
  const titleLower = title.toLowerCase();
  const urlLower = url.toLowerCase();

  if (titleLower.includes('french') || titleLower.includes('vf')) return 'vf';
  if (titleLower.includes('vostfr')) return 'vostfr';
  if (urlLower.includes('vf')) return 'vf';
  if (urlLower.includes('vostfr')) return 'vostfr';

  return 'vostfr'; // Default
}

// Save scraped anime to database
async function saveAnimeToDatabase(anime: ScrapedAnime): Promise<{ isNew: boolean; episodesAdded: number }> {
  let episodesAdded = 0;

  // Check if anime already exists
  const existing = await prisma.anime.findUnique({
    where: { slug: anime.slug },
    include: {
      seasons: {
        include: {
          episodesRel: {
            include: { videoSources: true }
          }
        }
      }
    }
  });

  if (existing) {
    // Update existing anime
    const season = existing.seasons[0];
    if (!season) {
      // Create season if missing
      await prisma.season.create({
        data: {
          animeId: existing.id,
          number: 1,
          title: 'Season 1',
          episodes: anime.episodes.length
        }
      });
    }

    // Add new episodes
    for (const ep of anime.episodes) {
      const existingEp = season?.episodesRel.find(e => e.number === ep.number);

      if (!existingEp) {
        // Create new episode
        const newEp = await prisma.episode.create({
          data: {
            seasonId: season?.id || existing.seasons[0]?.id || existing.id,
            number: ep.number,
            title: `Episode ${ep.number}`
          }
        });

        // Add video sources
        for (const url of ep.sources) {
          await prisma.videoSource.create({
            data: {
              episodeId: newEp.id,
              source: detectSource(url),
              url: url,
              language: detectLanguage(url, anime.title)
            }
          });
        }

        episodesAdded++;
      } else {
        // Check for new video sources
        for (const url of ep.sources) {
          const existingSource = existingEp.videoSources.find(vs => vs.url === url);

          if (!existingSource) {
            await prisma.videoSource.create({
              data: {
                episodeId: existingEp.id,
                source: detectSource(url),
                url: url,
                language: detectLanguage(url, anime.title)
              }
            });
            episodesAdded++;
          }
        }
      }
    }

    return { isNew: false, episodesAdded };
  }

  // Create new anime
  const newAnime = await prisma.anime.create({
    data: {
      slug: anime.slug,
      title: anime.title,
      description: anime.description || null,
      coverImage: anime.coverImage,
      type: anime.title.toLowerCase().includes('film') ? 'film' : 'anime',
      episodes: anime.episodes.length,
      seasons: {
        create: {
          number: 1,
          title: 'Season 1',
          episodes: anime.episodes.length,
          episodesRel: {
            create: anime.episodes.map(ep => ({
              number: ep.number,
              title: `Episode ${ep.number}`,
              videoSources: {
                create: ep.sources.map(url => ({
                  source: detectSource(url),
                  url: url,
                  language: detectLanguage(url, anime.title)
                }))
              }
            }))
          }
        }
      }
    }
  });

  return { isNew: true, episodesAdded: anime.episodes.length };
}

// Sleep helper
function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// Main sync function
async function syncAnimeSama(limit: number = 50, verbose: boolean = true) {
  console.log('🚀 Starting Anime-Sama.fun sync...');
  console.log(`📊 Limit: ${limit} animes`);

  // Create sync status
  const syncStatus = await prisma.syncStatus.create({
    data: { status: 'syncing' }
  });

  try {
    // Fetch posts
    const posts = await fetchAllPosts(limit);
    console.log(`✅ Fetched ${posts.length} posts`);

    let newAnimes = 0;
    let updatedAnimes = 0;
    let totalEpisodes = 0;

    // Process each post
    for (let i = 0; i < posts.length; i++) {
      const post = posts[i];
      if (verbose) {
        console.log(`\n[${i + 1}/${posts.length}] Processing: ${post.title.rendered}`);
      }

      // Scrape episodes
      const scraped = await scrapeAnimeEpisodes(post);

      if (scraped.episodes.length > 0) {
        // Save to database
        const result = await saveAnimeToDatabase(scraped);

        if (result.isNew) {
          newAnimes++;
          console.log(`  ✅ NEW: ${scraped.title} (${scraped.episodes.length} episodes)`);
        } else if (result.episodesAdded > 0) {
          updatedAnimes++;
          console.log(`  🔄 UPDATED: ${scraped.title} (+${result.episodesAdded} sources)`);
        } else {
          if (verbose) console.log(`  ⏭️ Exists: ${scraped.title}`);
        }

        totalEpisodes += scraped.episodes.length;
      } else {
        if (verbose) console.log(`  ⚠️ No episodes found: ${scraped.title}`);
      }

      // Rate limiting
      await sleep(200);
    }

    // Update sync status
    await prisma.syncStatus.update({
      where: { id: syncStatus.id },
      data: {
        status: 'idle',
        lastSyncAt: new Date(),
        animesUpdated: newAnimes + updatedAnimes,
        episodesAdded: totalEpisodes
      }
    });

    console.log('\n✅ Sync completed!');
    console.log(`📊 Summary:`);
    console.log(`   - New animes: ${newAnimes}`);
    console.log(`   - Updated animes: ${updatedAnimes}`);
    console.log(`   - Total episodes: ${totalEpisodes}`);

    return { newAnimes, updatedAnimes, totalEpisodes };
  } catch (error) {
    await prisma.syncStatus.update({
      where: { id: syncStatus.id },
      data: {
        status: 'error',
        errorMessage: String(error)
      }
    });

    console.error('❌ Sync failed:', error);
    throw error;
  }
}

// Run if called directly
const args = process.argv.slice(2);
const limit = parseInt(args.find(a => !a.startsWith('-')) || '50');
const verbose = args.includes('-v') || args.includes('--verbose');

syncAnimeSama(limit, verbose)
  .then(() => process.exit(0))
  .catch(() => process.exit(1));

