/**
 * Import script for anime data from vcc-anime-sources
 * 
 * Usage: bun run scripts/import-animes.ts
 */

import { PrismaClient } from '@prisma/client'
import fs from 'fs'
import path from 'path'

const prisma = new PrismaClient()

// Types for the anime data
interface EpisodeData {
  num: number
  sources: string[]
}

interface SeasonData {
  number: number
  vostfr: EpisodeData[]
  vf: EpisodeData[]
}

interface AnimeData {
  name: string
  slug: string
  url: string
  image: string
  type: string
  synopsis: string
  seasons: SeasonData[]
}

interface AnimeFullData {
  animes: AnimeData[]
}

// Video source detection
function detectSource(url: string): { source: string; priority: number } {
  if (url.includes('sibnet.ru')) return { source: 'sibnet', priority: 10 }
  if (url.includes('vidmoly')) return { source: 'vidmoly', priority: 9 }
  if (url.includes('sendvid.com')) return { source: 'sendvid', priority: 8 }
  if (url.includes('oneupload.to')) return { source: 'oneupload', priority: 7 }
  if (url.includes('myvi.tv') || url.includes('myvi.ru')) return { source: 'myvi', priority: 6 }
  if (url.includes('Smoothpre.com') || url.includes('movearnpre.com')) return { source: 'smoothpre', priority: 5 }
  if (url.includes('vk.com') || url.includes('vkvideo.ru')) return { source: 'vk', priority: 4 }
  if (url.includes('lpayer.embed4me.com')) return { source: 'lpayer', priority: 3 }
  if (url.includes('dingtezuni.com')) return { source: 'dingtezuni', priority: 2 }
  return { source: 'unknown', priority: 1 }
}

// Clean and validate URL
function cleanUrl(url: string): string | null {
  if (!url || url === ',' || url.trim() === '' || url.trim() === ',') return null
  return url.trim()
}

// Slugify string
function slugify(text: string): string {
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
}

async function importAnimes() {
  console.log('🚀 Starting anime import...')

  // Read the JSON file
  const dataPath = path.join('/home/z/vcc-anime-sources', 'animesama_full.json')
  console.log(`📂 Reading from: ${dataPath}`)

  const rawData = fs.readFileSync(dataPath, 'utf-8')
  const data: AnimeFullData = JSON.parse(rawData)

  console.log(`📊 Found ${data.animes.length} animes to import`)

  let importedAnimes = 0
  let importedSeasons = 0
  let importedEpisodes = 0
  let importedSources = 0
  let skippedAnimes = 0

  // Process in batches for better performance
  const batchSize = 50
  const totalBatches = Math.ceil(data.animes.length / batchSize)

  for (let batchIndex = 0; batchIndex < totalBatches; batchIndex++) {
    const batch = data.animes.slice(batchIndex * batchSize, (batchIndex + 1) * batchSize)

    for (const animeData of batch) {
      try {
        // Check if anime has valid content
        const hasContent = animeData.seasons?.some(s => 
          (s.vostfr?.some(e => e.sources?.some(url => cleanUrl(url))) ||
           s.vf?.some(e => e.sources?.some(url => cleanUrl(url))))
        )

        if (!hasContent) {
          skippedAnimes++
          continue
        }

        // Create or update anime
        const anime = await prisma.anime.upsert({
          where: { slug: animeData.slug || slugify(animeData.name) },
          update: {
            title: animeData.name,
            coverImage: animeData.image,
            description: animeData.synopsis !== 'Anime-Sama - Streaming et catalogage d\'animes et scans.' 
              ? animeData.synopsis 
              : null,
            type: animeData.type === 'film' ? 'film' : 'anime',
            episodes: animeData.seasons.reduce((total, s) => 
              total + Math.max(s.vostfr?.length || 0, s.vf?.length || 0), 0
            ),
          },
          create: {
            slug: animeData.slug || slugify(animeData.name),
            title: animeData.name,
            coverImage: animeData.image,
            description: animeData.synopsis !== 'Anime-Sama - Streaming et catalogage d\'animes et scans.' 
              ? animeData.synopsis 
              : null,
            type: animeData.type === 'film' ? 'film' : 'anime',
            episodes: animeData.seasons.reduce((total, s) => 
              total + Math.max(s.vostfr?.length || 0, s.vf?.length || 0), 0
            ),
          },
        })

        importedAnimes++

        // Process seasons
        for (const seasonData of animeData.seasons || []) {
          // Check if season has valid content
          const hasSeasonContent = 
            (seasonData.vostfr?.some(e => e.sources?.some(url => cleanUrl(url))) ||
             seasonData.vf?.some(e => e.sources?.some(url => cleanUrl(url))))

          if (!hasSeasonContent) continue

          const season = await prisma.season.upsert({
            where: {
              animeId_number: {
                animeId: anime.id,
                number: seasonData.number || 1,
              }
            },
            update: {
              episodes: Math.max(seasonData.vostfr?.length || 0, seasonData.vf?.length || 0),
            },
            create: {
              animeId: anime.id,
              number: seasonData.number || 1,
              title: `Saison ${seasonData.number || 1}`,
              episodes: Math.max(seasonData.vostfr?.length || 0, seasonData.vf?.length || 0),
            },
          })

          importedSeasons++

          // Process VOSTFR episodes
          for (const episodeData of seasonData.vostfr || []) {
            const validSources = episodeData.sources
              ?.map(cleanUrl)
              .filter((url): url is string => url !== null)

            if (!validSources?.length) continue

            const episode = await prisma.episode.upsert({
              where: {
                seasonId_number: {
                  seasonId: season.id,
                  number: episodeData.num,
                }
              },
              update: {},
              create: {
                seasonId: season.id,
                number: episodeData.num,
                title: `Épisode ${episodeData.num}`,
              },
            })

            importedEpisodes++

            // Add video sources
            for (const url of validSources) {
              const { source, priority } = detectSource(url)

              await prisma.videoSource.create({
                data: {
                  episodeId: episode.id,
                  source,
                  url,
                  language: 'vostfr',
                  priority,
                }
              })

              importedSources++
            }
          }

          // Process VF episodes
          for (const episodeData of seasonData.vf || []) {
            const validSources = episodeData.sources
              ?.map(cleanUrl)
              .filter((url): url is string => url !== null)

            if (!validSources?.length) continue

            const episode = await prisma.episode.upsert({
              where: {
                seasonId_number: {
                  seasonId: season.id,
                  number: episodeData.num,
                }
              },
              update: {},
              create: {
                seasonId: season.id,
                number: episodeData.num,
                title: `Épisode ${episodeData.num}`,
              },
            })

            importedEpisodes++

            // Add video sources
            for (const url of validSources) {
              const { source, priority } = detectSource(url)

              // Check if this source already exists for this episode
              const existing = await prisma.videoSource.findFirst({
                where: {
                  episodeId: episode.id,
                  url,
                  language: 'vf',
                }
              })

              if (!existing) {
                await prisma.videoSource.create({
                  data: {
                    episodeId: episode.id,
                    source,
                    url,
                    language: 'vf',
                    priority,
                  }
                })

                importedSources++
              }
            }
          }
        }

      } catch (error) {
        console.error(`❌ Error importing anime "${animeData.name}":`, error)
      }
    }

    // Progress update
    console.log(`⏳ Batch ${batchIndex + 1}/${totalBatches} processed (${Math.round((batchIndex + 1) / totalBatches * 100)}%)`)
  }

  console.log('\n✅ Import completed!')
  console.log(`📈 Statistics:`)
  console.log(`   - Animes imported: ${importedAnimes}`)
  console.log(`   - Skipped (no content): ${skippedAnimes}`)
  console.log(`   - Seasons created: ${importedSeasons}`)
  console.log(`   - Episodes created: ${importedEpisodes}`)
  console.log(`   - Video sources: ${importedSources}`)

  await prisma.$disconnect()
}

// Run the import
importAnimes().catch((error) => {
  console.error('Fatal error:', error)
  prisma.$disconnect()
  process.exit(1)
})

scripts/import-complete.ts.content:
/**
 * Import script for anime data from multiple sources
 * Combines animesama_full.json (multi-source VOSTFR) and sibnet-organized.json (VF+VOSTFR Sibnet)
 * 
 * Usage: bun run scripts/import-complete.ts
 */

import { PrismaClient } from '@prisma/client'
import fs from 'fs'
import path from 'path'

const prisma = new PrismaClient()

// Types for the anime data
interface EpisodeData {
  num: number
  sources: string[]
}

interface SeasonData {
  number: number
  vostfr: EpisodeData[]
  vf: EpisodeData[]
}

interface AnimeFullData {
  name: string
  slug: string
  url: string
  image: string
  type: string
  synopsis: string
  seasons: SeasonData[]
}

interface SibnetSource {
  id: string
  url: string
  embedUrl: string
  language: string
  thumbnail?: string
}

interface SibnetEpisode {
  sources: SibnetSource[]
}

interface SibnetSeason {
  episodes: Record<string, SibnetEpisode>
}

interface SibnetAnime {
  name: string
  seasons: Record<string, SibnetSeason>
}

interface SibnetData {
  [animeName: string]: SibnetAnime
}

// Video source detection
function detectSource(url: string): { source: string; priority: number } {
  if (url.includes('sibnet.ru')) return { source: 'sibnet', priority: 10 }
  if (url.includes('vidmoly')) return { source: 'vidmoly', priority: 9 }
  if (url.includes('sendvid.com')) return { source: 'sendvid', priority: 8 }
  if (url.includes('oneupload.to')) return { source: 'oneupload', priority: 7 }
  if (url.includes('myvi.tv') || url.includes('myvi.ru')) return { source: 'myvi', priority: 6 }
  if (url.includes('Smoothpre.com') || url.includes('movearnpre.com')) return { source: 'smoothpre', priority: 5 }
  if (url.includes('vk.com') || url.includes('vkvideo.ru')) return { source: 'vk', priority: 4 }
  if (url.includes('lpayer.embed4me.com')) return { source: 'lpayer', priority: 3 }
  if (url.includes('dingtezuni.com')) return { source: 'dingtezuni', priority: 2 }
  return { source: 'unknown', priority: 1 }
}

// Clean and validate URL
function cleanUrl(url: string): string | null {
  if (!url || url === ',' || url.trim() === '' || url.trim() === ',') return null
  return url.trim()
}

// Slugify string
function slugify(text: string): string {
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
}

// Normalize anime name for matching
function normalizeName(name: string): string {
  return name
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '')
}

async function importComplete() {
  console.log('🚀 Starting complete anime import...')

  // Read the JSON files
  const animesamaPath = path.join('/home/z/vcc-anime-sources', 'animesama_full.json')
  const sibnetPath = path.join('/home/z/vcc-anime-sources', 'sibnet-organized.json')

  console.log(`📂 Reading from: ${animesamaPath}`)
  console.log(`📂 Reading from: ${sibnetPath}`)

  const animesamaRaw = fs.readFileSync(animesamaPath, 'utf-8')
  const animesamaData: { animes: AnimeFullData[] } = JSON.parse(animesamaRaw)

  const sibnetRaw = fs.readFileSync(sibnetPath, 'utf-8')
  const sibnetData: SibnetData = JSON.parse(sibnetRaw)

  console.log(`📊 Found ${animesamaData.animes.length} animes in animesama_full.json`)
  console.log(`📊 Found ${Object.keys(sibnetData).length} animes in sibnet-organized.json`)

  // Create a map for sibnet data by normalized name
  const sibnetMap = new Map<string, SibnetAnime>()
  for (const [key, anime] of Object.entries(sibnetData)) {
    sibnetMap.set(normalizeName(anime.name || key), anime)
    sibnetMap.set(normalizeName(key), anime)
  }

  let importedAnimes = 0
  let importedSeasons = 0
  let importedEpisodes = 0
  let importedSources = 0
  let vfSourcesAdded = 0
  let skippedAnimes = 0

  // Clear existing data
  console.log('🗑️ Clearing existing data...')
  await prisma.videoSource.deleteMany()
  await prisma.episode.deleteMany()
  await prisma.season.deleteMany()
  await prisma.anime.deleteMany()

  // Process in batches
  const batchSize = 50
  const totalBatches = Math.ceil(animesamaData.animes.length / batchSize)

  for (let batchIndex = 0; batchIndex < totalBatches; batchIndex++) {
    const batch = animesamaData.animes.slice(batchIndex * batchSize, (batchIndex + 1) * batchSize)

    for (const animeData of batch) {
      try {
        // Check if anime has valid content
        const hasContent = animeData.seasons?.some(s => 
          (s.vostfr?.some(e => e.sources?.some(url => cleanUrl(url))) ||
           s.vf?.some(e => e.sources?.some(url => cleanUrl(url))))
        )

        if (!hasContent) {
          skippedAnimes++
          continue
        }

        const slug = animeData.slug || slugify(animeData.name)

        // Create anime
        const anime = await prisma.anime.create({
          data: {
            slug,
            title: animeData.name,
            coverImage: animeData.image,
            description: animeData.synopsis !== 'Anime-Sama - Streaming et catalogage d\'animes et scans.' 
              ? animeData.synopsis 
              : null,
            type: animeData.type === 'film' ? 'film' : 'anime',
            episodes: animeData.seasons.reduce((total, s) => 
              total + Math.max(s.vostfr?.length || 0, s.vf?.length || 0), 0
            ),
          },
        })

        importedAnimes++

        // Find matching sibnet data for VF sources
        const normalizedName = normalizeName(animeData.name)
        const sibnetAnime = sibnetMap.get(normalizedName)

        // Process seasons
        for (const seasonData of animeData.seasons || []) {
          const hasSeasonContent = 
            (seasonData.vostfr?.some(e => e.sources?.some(url => cleanUrl(url))) ||
             seasonData.vf?.some(e => e.sources?.some(url => cleanUrl(url))))

          if (!hasSeasonContent) continue

          const season = await prisma.season.create({
            data: {
              animeId: anime.id,
              number: seasonData.number || 1,
              title: `Saison ${seasonData.number || 1}`,
              episodes: Math.max(seasonData.vostfr?.length || 0, seasonData.vf?.length || 0),
            },
          })

          importedSeasons++

          // Track processed episodes to avoid duplicates
          const processedEpisodes = new Set<number>()

          // Process VOSTFR episodes from animesama_full.json (multiple sources)
          for (const episodeData of seasonData.vostfr || []) {
            const validSources = episodeData.sources
              ?.map(cleanUrl)
              .filter((url): url is string => url !== null)

            if (!validSources?.length) continue

            const epNumber = episodeData.num
            processedEpisodes.add(epNumber)

            const episode = await prisma.episode.create({
              data: {
                seasonId: season.id,
                number: epNumber,
                title: `Épisode ${epNumber}`,
              },
            })

            importedEpisodes++

            // Add video sources
            for (const url of validSources) {
              const { source, priority } = detectSource(url)

              await prisma.videoSource.create({
                data: {
                  episodeId: episode.id,
                  source,
                  url,
                  language: 'vostfr',
                  priority,
                }
              })

              importedSources++
            }

            // Check for VF from sibnet data
            if (sibnetAnime?.seasons?.[String(seasonData.number)]?.episodes?.[String(epNumber)]) {
              const sibnetEp = sibnetAnime.seasons[String(seasonData.number)].episodes[String(epNumber)]
              for (const src of sibnetEp.sources || []) {
                if (src.language === 'VF' && src.embedUrl) {
                  await prisma.videoSource.create({
                    data: {
                      episodeId: episode.id,
                      source: 'sibnet',
                      url: src.embedUrl,
                      language: 'vf',
                      priority: 10,
                    }
                  })
                  vfSourcesAdded++
                  importedSources++
                }
              }
            }
          }

          // Process remaining episodes (without VOSTFR from animesama)
          // Check sibnet for VF-only episodes
          if (sibnetAnime?.seasons?.[String(seasonData.number)]?.episodes) {
            for (const [epNum, epData] of Object.entries(sibnetAnime.seasons[String(seasonData.number)].episodes)) {
              const epNumber = parseInt(epNum)
              if (processedEpisodes.has(epNumber)) continue

              const vfSources = (epData as SibnetEpisode).sources?.filter(s => s.language === 'VF') || []
              const vostfrSources = (epData as SibnetEpisode).sources?.filter(s => s.language === 'VOSTFR') || []

              if (vfSources.length === 0 && vostfrSources.length === 0) continue

              const episode = await prisma.episode.create({
                data: {
                  seasonId: season.id,
                  number: epNumber,
                  title: `Épisode ${epNumber}`,
                },
              })

              importedEpisodes++

              // Add VF sources
              for (const src of vfSources) {
                if (src.embedUrl) {
                  await prisma.videoSource.create({
                    data: {
                      episodeId: episode.id,
                      source: 'sibnet',
                      url: src.embedUrl,
                      language: 'vf',
                      priority: 10,
                    }
                  })
                  vfSourcesAdded++
                  importedSources++
                }
              }

              // Add VOSTFR sources
              for (const src of vostfrSources) {
                if (src.embedUrl) {
                  await prisma.videoSource.create({
                    data: {
                      episodeId: episode.id,
                      source: 'sibnet',
                      url: src.embedUrl,
                      language: 'vostfr',
                      priority: 10,
                    }
                  })
                  importedSources++
                }
              }
            }
          }
        }

      } catch (error) {
        console.error(`❌ Error importing anime "${animeData.name}":`, error)
      }
    }

    console.log(`⏳ Batch ${batchIndex + 1}/${totalBatches} processed (${Math.round((batchIndex + 1) / totalBatches * 100)}%)`)
  }

  console.log('\n✅ Import completed!')
  console.log(`📈 Statistics:`)
  console.log(`   - Animes imported: ${importedAnimes}`)
  console.log(`   - Skipped (no content): ${skippedAnimes}`)
  console.log(`   - Seasons created: ${importedSeasons}`)
  console.log(`   - Episodes created: ${importedEpisodes}`)
  console.log(`   - Video sources: ${importedSources}`)
  console.log(`   - VF sources added from sibnet: ${vfSourcesAdded}`)

  await prisma.$disconnect()
}

// Run the import
importComplete().catch((error) => {
  console.error('Fatal error:', error)
  prisma.$disconnect()
  process.exit(1)
})
